if(preg_match('#^/s/([a-z0-9_-]+)(?:/([a-z0-9_/-]+))?$#',$path,$m)){$siteSlug=$m[1];$pageSlug=trim($m[2]??'','/');$q=db()->prepare("SELECT p.*,s.name site_name,s.tracking_enabled FROM site_pages p JOIN sites s ON s.id=p.site_id WHERE s.slug=? AND s.status='published' AND p.status='published' AND (p.slug=? OR (?='' AND p.is_home=1)) LIMIT 1");$q->execute([$siteSlug,$pageSlug,$pageSlug]);$p=$q->fetch();if(!$p){http_response_code(404);exit('Page not found');}$js=(string)$p['custom_js'];?><!doctype html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title><?=e($p['title']?:$p['name'])?></title><meta name="description" content="<?=e($p['meta_description'])?>"><style><?=$p['css']?></style></head><body><?=$p['html']?><?php if($p['tracking_enabled']):?><script>(()=>{let v=0,start=Date.now(),q=Object.fromEntries(new URLSearchParams(location.search));fetch('/track/site',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({page_id:<?=$p['id']?>,event:'view',referrer:document.referrer,query:q})}).then(r=>r.json()).then(x=>v=x.view_id||0);function send(){if(!v)return;navigator.sendBeacon('/track/site',new Blob([JSON.stringify({page_id:<?=$p['id']?>,event:'engage',view_id:v,seconds:Math.round((Date.now()-start)/1000)})],{type:'application/json'}))}addEventListener('pagehide',send);setInterval(send,15000)})()</script><?php endif?><?php if($js!==''):?><script><?=$js?></script><?php endif?></body></html><?php exit;}
