if(preg_match('#^/sites/pages/(\d+)/edit$#',$path,$m)){$p=site_page_row((int)$m[1]);require_permission('sites.edit');if($method==='POST'){verify_csrf();$project=(string)post('project_json');$html=(string)post('html');$css=(string)post('css');$customJs=(user()['is_admin']??false)?(string)post('custom_js'):(string)$p['custom_js'];$v=db()->prepare('SELECT COALESCE(MAX(version_number),0)+1 FROM site_page_versions WHERE page_id=?');$v->execute([$p['id']]);$version=(int)$v->fetchColumn();db()->prepare('INSERT INTO site_page_versions(page_id,version_number,project_json,html,css,custom_js,created_by) VALUES(?,?,?,?,?,?,?)')->execute([$p['id'],$version,$project,$html,$css,$customJs,user()['id']]);db()->prepare("UPDATE site_pages SET name=?,title=?,meta_description=?,project_json=?,html=?,css=?,custom_js=?,status=IF(?='publish','published',status),published_at=IF(?='publish',NOW(),published_at),updated_by=? WHERE id=?")->execute([trim((string)post('name')),trim((string)post('title')),trim((string)post('meta_description')),$project,$html,$css,$customJs,post('action'),post('action'),user()['id'],$p['id']]);audit(post('action'),'site_page',(int)$p['id'],['version'=>$version]);flash('success','Page saved.');redirect('/sites/pages/'.$p['id'].'/edit');}$forms=db()->query("SELECT slug,name FROM crm_forms WHERE active=1 ORDER BY name")->fetchAll();$meetings=db()->query("SELECT slug,name FROM booking_meeting_types WHERE active=1 ORDER BY name")->fetchAll();layout('Visual page editor',function()use($p,$forms,$meetings){?><link rel="stylesheet" href="https://unpkg.com/grapesjs/dist/css/grapes.min.css"><div class="actions"><h1 style="margin:0"><?=e($p['name'])?></h1><span class="spacer"></span><a class="btn secondary" href="/sites/<?=$p['site_id']?>">Back</a></div><form id="site-editor-form" method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><input type="hidden" name="project_json"><input type="hidden" name="html"><input type="hidden" name="css"><div class="card form-grid"><label>Name<input name="name" value="<?=e($p['name'])?>"></label><label>Browser title<input name="title" value="<?=e($p['title'])?>"></label><label class="full">Meta description<input name="meta_description" value="<?=e($p['meta_description'])?>"></label><?php if(user()['is_admin']):?><label class="full">Custom JavaScript (administrator only)<textarea name="custom_js"><?=e($p['custom_js'])?></textarea></label><?php endif?></div><div class="site-builder-shell"><aside id="site-blocks"></aside><div id="gjs"></div></div><div class="actions card"><button name="action" value="save">Save draft</button><button name="action" value="publish">Save and publish</button></div></form><script>window.siteEditorData=<?=json_encode(['project'=>json_decode((string)$p['project_json'],true),'html'=>$p['html'],'css'=>$p['css'],'forms'=>$forms,'meetings'=>$meetings],JSON_HEX_TAG|JSON_HEX_APOS|JSON_HEX_AMP|JSON_HEX_QUOT)?>;</script><script src="https://unpkg.com/grapesjs"></script><script src="/assets/site-builder.js"></script><?php });exit;}
if(preg_match('#^/sites/(\d+)/analytics$#',$path,$m)){$site=site_row((int)$m[1]);$q=db()->prepare('SELECT p.name,COUNT(v.id) views,COUNT(DISTINCT s.visitor_id) visitors,COALESCE(SUM(v.engaged_seconds),0) engaged FROM site_pages p LEFT JOIN site_page_views v ON v.page_id=p.id LEFT JOIN site_sessions s ON s.id=v.session_id WHERE p.site_id=? GROUP BY p.id ORDER BY views DESC');$q->execute([$site['id']]);$rows=$q->fetchAll();layout('Site analytics',function()use($site,$rows){?><h1><?=e($site['name'])?> analytics</h1><div class="card"><table><thead><tr><th>Page</th><th>Views</th><th>Visitors</th><th>Engaged time</th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><?=e($r['name'])?></td><td><?=$r['views']?></td><td><?=$r['visitors']?></td><td><?=round($r['engaged']/60,1)?> minutes</td></tr><?php endforeach?></tbody></table></div><?php });exit;}
